import{c as t,Q as a,j as s,m as i}from"./chunks/framework.BPKcPtvA.js";const u=JSON.parse(`{"title":"Audit log","description":"What's recorded across surfaces, what's intentionally not.","frontmatter":{"title":"Audit log","description":"What's recorded across surfaces, what's intentionally not."},"headers":[],"relativePath":"policy/audit-log.md","filePath":"policy/audit-log.md","lastUpdated":1780245214000}`),o={name:"policy/audit-log.md"};function d(r,e,n,c,l,h){return a(),s("div",null,[...e[0]||(e[0]=[i(`<h1 id="audit-log" tabindex="-1">Audit log <a class="header-anchor" href="#audit-log" aria-label="Permalink to &quot;Audit log&quot;">​</a></h1><p>Every state-mutating action on every agentic surface writes to a single <strong>append-only WORM-style audit log</strong>. The same <code>agent_audit_events</code> table backs HavenBot, MCP, OpenClaw, and the hosted-checkout issuer side.</p><p>Read tools intentionally <strong>do not</strong> log — that&#39;s a privacy floor. Forensic completeness for state-changing actions is the wall.</p><h2 id="what-s-logged" tabindex="-1">What&#39;s logged <a class="header-anchor" href="#what-s-logged" aria-label="Permalink to &quot;What&#39;s logged&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Event type</th><th>When it fires</th><th>Carries</th></tr></thead><tbody><tr><td><code>propose_*</code></td><td>LLM proposes an action (before user confirms)</td><td>tool name, args summary, action hash, requestedAtSec</td></tr><tr><td><code>permit_granted</code></td><td>User confirms; UserOp signed and submitted</td><td>tool name, surface, source, tx hash (after settlement)</td></tr><tr><td><code>permit_attempted</code></td><td>User confirms but UserOp failed (revert or timeout)</td><td>tool name, surface, source, error code</td></tr><tr><td><code>tier_transition</code></td><td>User changes their tier</td><td>from tier, to tier</td></tr><tr><td><code>pause_triggered</code></td><td>Pause cascade fires</td><td>manual / auto / breach</td></tr><tr><td><code>pause_lifted</code></td><td>Resume cascade fires</td><td>(manual only — auto-pauses require manual resume)</td></tr><tr><td><code>breach_detected</code></td><td>Policy-bound cron observes a threshold breach (designed — that cron is disabled in every deployment today)</td><td>breach type, encrypted handle (no cleartext)</td></tr><tr><td><code>policy_template_built</code></td><td>User mints a new session-key scope</td><td>scope summary, validity window</td></tr><tr><td><code>device_code_consumed</code></td><td>MCP device-flow login succeeds</td><td>client metadata, scope claims</td></tr><tr><td><code>telegram_link_consumed</code></td><td>Telegram bot <code>/link</code> succeeds</td><td>chat_id, user_id</td></tr><tr><td><code>checkout_created</code></td><td>Issuer mints a checkout</td><td>session_id, token, amount</td></tr><tr><td><code>checkout_paid</code></td><td>Buyer settles a checkout</td><td>session_id, buyer_wallet, tx_hash</td></tr><tr><td><code>checkout_expired</code></td><td>Session TTL elapses without payment</td><td>session_id</td></tr><tr><td><code>checkout_cancelled</code></td><td>Issuer cancels an unredeemed session</td><td>session_id</td></tr></tbody></table><h2 id="what-s-not-logged" tabindex="-1">What&#39;s NOT logged <a class="header-anchor" href="#what-s-not-logged" aria-label="Permalink to &quot;What&#39;s NOT logged&quot;">​</a></h2><p>Deliberate omissions:</p><ul><li><strong>Read calls.</strong> Reading your own portfolio, yields, audit, etc. emits no audit row. Tracking every &quot;user looked at portfolio&quot; turns the audit log into a surveillance ledger.</li><li><strong>Encrypted balance handles.</strong> Logged actions reference token addresses + the <em>fact</em> of a state mutation, not the encrypted amount.</li><li><strong>Cleartext votes.</strong> Encrypted governance votes log the <em>fact</em> of a vote (<code>permit_granted</code> row with <code>tool: &#39;governance.cast_vote&#39;</code>) but not the cleartext yes/no.</li><li><strong>LLM chat transcripts.</strong> HavenBot&#39;s chat history is server-managed but separate from the audit log. You can clear chat without affecting audit.</li><li><strong>Permit grant content.</strong> A permit row says &quot;permit minted for handle X with TTL Y&quot;; it doesn&#39;t capture the resulting plaintext.</li></ul><h2 id="query-interface" tabindex="-1">Query interface <a class="header-anchor" href="#query-interface" aria-label="Permalink to &quot;Query interface&quot;">​</a></h2><h3 id="via-havenbot" tabindex="-1">Via HavenBot <a class="header-anchor" href="#via-havenbot" aria-label="Permalink to &quot;Via HavenBot&quot;">​</a></h3><blockquote><p>Show my agent audit log. Show audit rows from MCP in the last 7 days. Show only failed agent actions. Export my audit log.</p></blockquote><h3 id="via-mcp" tabindex="-1">Via MCP <a class="header-anchor" href="#via-mcp" aria-label="Permalink to &quot;Via MCP&quot;">​</a></h3><div class="language-ts vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">ts</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">mcp.read.</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">audit</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">({ cursor: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;...&#39;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, limit: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">50</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, filter: { surface: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;mcp&#39;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> } })</span></span></code></pre></div><p>Returns cursor-paginated rows. The cursor is a tuple <code>(createdAt, id)</code> for tie-breaking on burst writes that share a sub-ms <code>defaultNow()</code> timestamp (port-time fix from P1).</p><h3 id="via-dashboard" tabindex="-1">Via dashboard <a class="header-anchor" href="#via-dashboard" aria-label="Permalink to &quot;Via dashboard&quot;">​</a></h3><p><code>/agent → Audit</code> opens a paginated table with filter chips for surface, tool, outcome, date range.</p><h2 id="source-attribution" tabindex="-1">Source attribution <a class="header-anchor" href="#source-attribution" aria-label="Permalink to &quot;Source attribution&quot;">​</a></h2><p>Every <code>permit_granted</code> row carries a server-derived <code>source</code> field that says <strong>how</strong> the confirmation happened:</p><table tabindex="0"><thead><tr><th><code>source</code></th><th>Meaning</th></tr></thead><tbody><tr><td><code>dashboard_passkey</code></td><td>Dashboard ConfirmModal + passkey ceremony</td></tr><tr><td><code>dashboard_session_key</code></td><td>Dashboard ConfirmModal + session-key signature (Confirm-per-action tier)</td></tr><tr><td><code>policy_bound_cron</code></td><td>Cron policy engine signed within bounds (designed — cron disabled in every deployment today)</td></tr><tr><td><code>scoped_autonomy</code></td><td>Broker daemon signed within the Scoped session&#39;s per-trade cap + TTL (the live autonomous path)</td></tr><tr><td><code>mcp_broker</code></td><td>MCP propose → user confirmed on dashboard or host UI</td></tr><tr><td><code>telegram_inline</code></td><td>Telegram inline-button confirmation (tier 1 ≤$200)</td></tr><tr><td><code>mini_app</code></td><td>Telegram Mini App OTP confirmation (tier 2 $200-$5K)</td></tr></tbody></table><p>The <code>source</code> is <strong>server-derived</strong> from the auth path — investors and bot workers cannot spoof it. A <code>policy_bound_cron</code> row guarantees the cron actually signed (not just that you said it did).</p><h2 id="append-only-semantics" tabindex="-1">Append-only semantics <a class="header-anchor" href="#append-only-semantics" aria-label="Permalink to &quot;Append-only semantics&quot;">​</a></h2><p>The <code>agent_audit_events</code> table is intentionally <strong>append-only</strong>:</p><ul><li>The Drizzle schema has no <code>updatedAt</code> column.</li><li>The <code>IAgentAuditRepository</code> interface exposes only <code>append</code> + <code>findByUserId</code> (no update / delete).</li><li>All writes go through <code>AppendAuditEventUseCase</code> — centralised.</li><li>Database-level: <code>REVOKE UPDATE, DELETE ON agent_audit_events FROM muhaven_app</code> is set in the production deploy script.</li></ul><p>The append-only property is the load-bearing forensic invariant: you (or a regulator, or a forensic reviewer) can replay the audit log and trust it wasn&#39;t tampered with after the fact.</p><h2 id="cursor-pagination" tabindex="-1">Cursor pagination <a class="header-anchor" href="#cursor-pagination" aria-label="Permalink to &quot;Cursor pagination&quot;">​</a></h2><p>Pagination uses <strong>tuple comparison</strong> to avoid silently dropping rows that share a sub-ms timestamp:</p><div class="language-sql vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">sql</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">WHERE</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> (created_at </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&gt;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> $cursor_at)</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">   OR</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> (created_at </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> $cursor_at </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">AND</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> id </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&gt;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> $cursor_id)</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">ORDER BY</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> created_at </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">ASC</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, id </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">ASC</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">LIMIT</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> $</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">limit</span></span></code></pre></div><p>A naive <code>gt(createdAt)</code> would lose rows on burst writes (e.g., the four-surface pause cascade). The tuple comparison is the safety net.</p><h2 id="cross-user-audit-access" tabindex="-1">Cross-user audit access <a class="header-anchor" href="#cross-user-audit-access" aria-label="Permalink to &quot;Cross-user audit access&quot;">​</a></h2><p>Audit reads are <strong>self-only</strong>. A compliance officer can read their own audit; they cannot read another user&#39;s audit even with their consent. There&#39;s no cross-user permit-gated read path today.</p><h2 id="where-next" tabindex="-1">Where next <a class="header-anchor" href="#where-next" aria-label="Permalink to &quot;Where next&quot;">​</a></h2><ul><li><a href="/policy/tiered-autonomy">Tiered autonomy</a> — how tier transitions log.</li><li><a href="/policy/pause">The /pause kill-switch</a> — pause cascade and audit rows.</li><li><a href="/policy/session-keys">Session keys</a> — what session-key activity records.</li></ul>`,32)])])}const g=t(o,[["render",d]]);export{u as __pageData,g as default};
